class Solution {
public:
    int countDigitOne(int n) {
        int count = 0;
        for (long long i = 1; i <= n; i *= 10) {
            count += (n / i) / 10 * i + min(max(n % i - i + 1, 0), i);
        }
        return count;
    }
};
```
